// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

// solhint-disable avoid-low-level-calls

import "../IL1Bridge.sol";
import "./IArbOutbox.sol";
import "./IArbInbox.sol";
import "../../common/Errors.sol";
import "../common/EnvelopeLib.sol";

contract L1ArbitrumBridgeConnector is IL1Bridge {
    IArbOutbox public immutable outbox;
    IArbInbox public immutable inbox;
    address private _l2AppSender;
    constructor(IArbOutbox _outbox, IArbInbox _inbox) {
        outbox = _outbox;
        inbox = _inbox;
    }

    function sendMessageToL2(address _destination, bytes calldata _data, uint256 _gasLimit) external {
        // Verify envelope fromApp == msg.sender
        (, bytes memory envelope, ) = EnvelopeLib.decodeWrapper(_data);
        (address from, ) = EnvelopeLib.decodeEnvelope(envelope);
        require(from == msg.sender, InvalidCaller("not app sender", from, msg.sender));
        inbox.createRetryableTicket(
            _destination,
            0,
            2000000000,
            msg.sender,
            msg.sender,
            _gasLimit,
            1,
            _data
        );
    }

    function l2Sender() external view returns (address) {
        return outbox.l2ToL1Sender();
    }

    function l2AppSender() external view returns (address) {
        return _l2AppSender;
    }


    // Each bridge message is encoded as:
    // (bytes32[] proof, uint256 index, address l2Sender, address to, uint256 l2Block,
    //  uint256 l1Block, uint256 l2Timestamp, uint256 value, bytes data)
    function applyL2ToL1Messages(bytes[] calldata bridgeMessages) external returns (uint256 applied) {
        for (uint256 i = 0; i < bridgeMessages.length; i++) {
            (
                bytes32[] memory proof,
                uint256 index,
                address l2SenderAddress,
                address to,
                uint256 l2Block,
                uint256 l1Block,
                uint256 l2Timestamp,
                uint256 value,
                bytes memory data
            ) = abi.decode(bridgeMessages[i], (bytes32[], uint256, address, address, uint256, uint256, uint256, uint256, bytes));
            outbox.executeTransaction(
                proof,
                index,
                l2SenderAddress,
                to,
                l2Block,
                l1Block,
                l2Timestamp,
                value,
                data
            );
            applied++;
        }
    }

    function forwardFromL2(address to, bytes calldata data, uint256 gasLimit) external {
        (gasLimit);
        require(msg.sender == address(outbox), InvalidCaller("not L2 bridge", address(outbox), msg.sender));
        (address appSender, bytes memory inner) = EnvelopeLib.decodeEnvelope(data);
        address prev = _l2AppSender;
        _l2AppSender = appSender;
        (bool success, bytes memory reason) = to.call(inner);
        _l2AppSender = prev;
        require(success, ExternalCallReverted("L2->L1 forward", to, reason));
    }
}

project/src/bridges/arbitrum/L2ArbitrumB.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

// solhint-disable avoid-low-level-calls

import "./ArbSys.sol";
import "../IL2Bridge.sol";
import "../../common/Errors.sol";
import "../common/EnvelopeLib.sol";

contract L2ArbitrumBridgeConnector is IL2Bridge {
    address private _tmpL1Sender;
    address private _tmpL1AppSender;

    function l1Sender() external view returns (address) {
        return _tmpL1Sender;
    }

    function l1AppSender() external view returns (address) {return _tmpL1AppSender;}

    function sendMessageToL1(address _destination, bytes calldata _data, uint256) external returns (uint256) {
        // Gate by verifying the provided wrapper encodes an app-level sender equal to msg.sender
        (, bytes memory envelope,) = EnvelopeLib.decodeWrapper(_data);
        (address from,) = EnvelopeLib.decodeEnvelope(envelope);
        require(from == msg.sender, InvalidCaller("not app sender", from, msg.sender));
        // ticketId tracks the L1 message.
        uint256 ticketId = ArbSys(address(100)).sendTxToL1(_destination, _data);
        return ticketId;
    }

    /// @notice Forward an L1->L2 message to a target, capturing the true L1 sender from Arbitrum precompile.
    /// @dev On Arbitrum, L1 originating calls arrive with address aliasing; the canonical L1 sender is exposed by ArbSys.
    function forwardFromL1(address to, bytes calldata data, uint256 gasLimit) external {
        (gasLimit);
        address prev = _tmpL1Sender;
        address sender = ArbSys(address(100)).arbTxL1Sender();
        // When not called from an L1 origin, sender may be zero; protect by requiring non-zero to mitigate misuse.
        require(sender != address(0), InvalidCaller("not L1-originated", address(0), msg.sender));
        _tmpL1Sender = sender;
        (address appSender, bytes memory inner) = EnvelopeLib.decodeEnvelope(data);
        address prevApp = _tmpL1AppSender;
        _tmpL1AppSender = appSender;
        (bool success, bytes memory reason) = to.call(inner);
        _tmpL1AppSender = prevApp;
        _tmpL1Sender = prev;
        require(success, ExternalCallReverted("L1->L2 forward", to, reason));
    }

}

